11884   static bool isVectorizable(RecurKind Kind, Instruction *I) {
11885     if (Kind == RecurKind::None)
11886       return false;
11887 
11888     // Integer ops that map to select instructions or intrinsics are fine.
11889     if (RecurrenceDescriptor::isIntMinMaxRecurrenceKind(Kind) ||
11890         isBoolLogicOp(I))
11891       return true;
11892 
11893     if (Kind == RecurKind::FMax || Kind == RecurKind::FMin) {
11894       // FP min/max are associative except for NaN and -0.0. We do not
11895       // have to rule out -0.0 here because the intrinsic semantics do not
11896       // specify a fixed result for it.
11897       return I->getFastMathFlags().noNaNs();
11898     }
11899 
11900     return I->isAssociative();
11901   }
